  "METROPOLITANA":{"SANTIAGO":"SANTIAGO","PROVIDENCIA":"SANTIAGO","NUNOA":"SANTIAGO","LAS CONDES":"SANTIAGO","VITACURA":"SANTIAGO","LO BARNECHEA":"SANTIAGO","LA REINA":"SANTIAGO","PENALOLEN":"SANTIAGO","LA FLORIDA":"SANTIAGO","PUENTE ALTO":"SANTIAGO","SAN JOSE DE MAIPO":"CORDILLERA","PIRQUE":"CORDILLERA","COLINA":"CHACABUCO","LAMPA":"CHACABUCO","TILTIL":"CHACABUCO","SAN BERNARDO":"MAIPO","BUIN":"MAIPO","CALERA DE TANGO":"MAIPO","PAINE":"MAIPO","ISLA DE MAIPO":"TALAGANTE","TALAGANTE":"TALAGANTE","PENAFLOR":"TALAGANTE","EL MONTE":"TALAGANTE","PADRE HURTADO":"TALAGANTE","MELIPILLA":"MELIPILLA","MARIA PINTO":"MELIPILLA","CURACAVI":"MELIPILLA","ALHUE":"MELIPILLA","SAN PEDRO":"MELIPILLA"}
